Here's a minimal example of autodiffing object-oriented code using Python:

```python
import numpy as np

class Variable:
    def __init__(self, value):
        self.value = value
        self.grad = None

    def __repr__(self):
        return f"Variable({self.value})"

    def backward(self):
        raise NotImplementedError

class Constant(Variable):
    def backward(self):
        return None

class Sum(Variable):
    def __init__(self, *args):
        super().__init__(np.sum([arg.value for arg in args]))
        self.args = args

    def backward(self):
        return [arg.backward() + self.grad for arg in self.args]

class Mul(Variable):
    def __init__(self, *args):
        super().__init__(np.prod([arg.value for arg in args]))
        self.args = args

    def backward(self):
        return [arg.value * self.grad for arg in self.args]

def autodiff(func, *args):
    output = func(*[arg.value for arg in args])
    output = Variable(output)
    for arg in args:
        arg.grad = 1.0
    output.backward()
    return output.value

