Here's an example of an updated `BaseRepository` class that supports finding by a dynamic field:

```csharp
public abstract class BaseRepository<T> : IRepository<T> where T : class
{
    protected readonly DbContext _context;

    public BaseRepository(DbContext context)
    {
        _context = context;
    }

    public virtual IQueryable<T> GetAll()
    {
        return _context.Set<T>();
    }

    public virtual async Task<T> GetByIdAsync(int id)
    {
        return await _context.Set<T>().FindAsync(id);
    }

    public virtual async Task<T> FindAsync(Expression<Func<T, bool>> predicate)
    {
        return await _context.Set<T>().FirstOrDefaultAsync(predicate);
    }

    public virtual async Task<IQueryable<T>> FindByDynamicAsync(Expression<Func<T, object>> dynamicField, object value)
    {
        var parameter = Expression.Parameter(typeof(T));
        var memberExpression = Expression.PropertyOrField(parameter, dynamicField.Name);
        var lambda = Expression.Lambda(memberExpression, parameter);
        var dynamicPredicate = Expression.Equal(lambda.Body, Expression.Constant(value));

        return await _context.Set<T>().Where(Expression.Lambda<Func<T, bool>>(dynamicPredicate, parameter));
    }
}
```

