from abc import ABC, abstractmethod
from typing import List, Dict

# Define a base class for relational algebra operations
class RelationalAlgebraOperation(ABC):
    @abstractmethod
    def evaluate(self, relations: List[Dict]) -> List[Dict]:
        pass

# Define a class for projection
class Projection(RelationalAlgebraOperation):
    def __init__(self, attributes: List[str]):
        self.attributes = attributes

    def evaluate(self, relations: List[Dict]) -> List[Dict]:
        # Evaluate projection operation
        return [dict((k, v) for k, v in relation.items() if k in self.attributes) for relation in relations]

# Define a class for selection
class Selection(RelationalAlgebraOperation):
    def __init__(self, condition: str):
        self.condition = condition

